import { StrictStyleOptions } from 'botframework-webchat-api';
import { toByteArray } from 'base64-js';

const DEFAULT_IMAGE_BASE64 =
  '';
const DEFAULT_IMAGE_TYPE = 'image/gif';

let defaultImageBlobURL;

export default function createTypingAnimationStyle({
  typingAnimationBackgroundImage,
  typingAnimationHeight,
  typingAnimationWidth
}: StrictStyleOptions) {
  defaultImageBlobURL ||
    (defaultImageBlobURL = URL.createObjectURL(
      new Blob([toByteArray(DEFAULT_IMAGE_BASE64)], { type: DEFAULT_IMAGE_TYPE })
    ));

  const backgroundImage = typingAnimationBackgroundImage || `url('${defaultImageBlobURL}')`;

  return {
    backgroundImage,
    backgroundRepeat: 'no-repeat',
    height: typingAnimationHeight,
    width: typingAnimationWidth
  };
}
